// Preparar Input
// Lê o body do webhook e monta o array de actions esperado pelo
// Sub - Gerar Follow-up Inteligente (Parse Input lê inputData.actions)
const body = $input.first().json.body || $input.first().json;

const action = {
  id: 'single',
  parceiro:               body.parceiro               || '',
  ponto_focal:            body.ponto_focal             || '',
  produto:                body.produto                 || '',
  status:                 body.status                  || '',
  resumo_negociacao:      body.resumo_negociacao        || '',
  observacoes_gerais:     body.observacoes_gerais       || '',
  status_followup_norm:   body.status_followup          || '',
  data_followup_realizado: body.data_followup_realizado || '',
  ultima_cadencia_feita:  body.ultima_cadencia_feita    || '',
  risco:                  body.risco                   || 'baixo',
  bucket:                 body.prioridade              || 'podeEsperar'
};

return [{ json: { actions: [action] } }];

// Formatar Resposta
// O subworkflow retorna { id, mensagem_pronta } — normaliza para { status, mensagem }
const result = $input.first().json;

const mensagem = String(
  result.mensagem_pronta ||
  result.mensagem         ||
  result.text             ||
  result.output           ||
  ''
).trim();

if (!mensagem) {
  return [{ json: { status: 'erro', mensagem: 'Não foi possível gerar o follow-up.' } }];
}

return [{ json: { status: 'ok', mensagem } }];
